// Local and Remote Authentication Management
package ldapmanager

import (
	"context"

	"github.com/arminguenther/xeruspower-go/auth/ldapsrv/ldapserversettings"
	"github.com/arminguenther/xeruspower-go/idl"
)

const (
	ERR_CYCLIC_DEP            int32 = 1 // Cyclic dependency in server list
	ERR_INVALID_CFG           int32 = 2 // The server configuration is invalid
	ERR_SERVER_UNSPECIFIED    int32 = 1 // Unspecified error
	ERR_SERVER_UNREACHABLE    int32 = 3 // LDAP server could not be contacted
	ERR_AUTHENTICATION_FAILED int32 = 4 // User could not be authenticated
	ERR_NO_ROLES              int32 = 5 // No roles are defined for the user
	ERR_NO_KNOWN_ROLES        int32 = 6 // No known rules are defined for the user
)

// LDAP server configuration interface
type LdapManager interface {
	idl.Object

	// Get a list of LDAP server settings
	//
	//	@return list of ldapsrv.ServerSettings
	GetLdapServers(ctx context.Context) ([]ldapserversettings.ServerSettings, error)

	// Sets a list of LDAP servers.
	// Any existing LDAP Server configuration will be cleared / overwritten.
	//
	//	@return 0                            on success
	//	@return ERR_CYCLIC_DEP            in case of cyclic dependency
	//	@return ERR_INVALID_CFG           in case of invalid configuration
	SetLdapServers(ctx context.Context, serverList []ldapserversettings.ServerSettings) (int32, error)

	// Tests an LDAP server configuration.
	//
	//	@return 0                                    on success
	//	@return ERR_SERVER_UNSPECIFIED            an unspecified error occurred
	//	@return ERR_INVALID_CFG                   LDAP server configuration is invalid (reused from setLdapServers)
	//	@return ERR_SERVER_UNREACHABLE            LDAP server could not be contacted
	//	@return ERR_AUTHENTICATION_FAILED         user could not be authenticated
	//	@return ERR_NO_ROLES                      no roles are defined for the user
	//	@return ERR_NO_KNOWN_ROLES                no known roles are defined for the user
	TestLdapServer(ctx context.Context, username string, password string, settings ldapserversettings.ServerSettings) (ret int32, diagMsg string, err error)
}
